declare module '*?format=avif' {
  const src: string
  export default src
}

declare module '*?format=webp' {
  const src: string
  export default src
}

declare module '*?format=avif&w=*' {
  const src: string
  export default src
}

declare module '*?format=webp&w=*' {
  const src: string
  export default src
}

declare module '*?w=*' {
  const src: string
  export default src
}
